#include <stdio.h>
#include <string.h>
#define MAX 10000
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char S[MAX + 1];
        scanf("%s", S);
        int n = strlen(S);
        int maxLen = 0;
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                for (int k = j + 1; k < n; k++) {
                    if (S[i] == '#' && S[j] == '#' && S[k] == '#') {
                        int len = 0;
                        char c1 = '\0', c2 = '\0', c3 = '\0', c4 = '\0';
                        for (int p = 0; p < i; p++) {
                            if (c1 == '\0') c1 = S[p];
                            if (S[p] == c1) len++;
                        }
                        for (int p = i + 1; p < j; p++) {
                            if (c2 == '\0') c2 = S[p];
                            if (S[p] == c2) len++;
                        }
                        for (int p = j + 1; p < k; p++) {
                            if (c3 == '\0') c3 = S[p];
                            if (S[p] == c3) len++;
                        }
                        for (int p = k + 1; p < n; p++) {
                            if (c4 == '\0') c4 = S[p];
                            if (S[p] == c4) len++;
                        }
                        maxLen = (maxLen > len + 3) ? maxLen : len + 3;
                    }
                }
            }
        }
        printf("%d\n", maxLen);
    }
    return 0;
}

