def solve(S):
    n = len(S)
    maxLen = 0
    for i in range(n):
        for j in range(i + 1, n):
            for k in range(j + 1, n):
                if S[i] == '#' and S[j] == '#' and S[k] == '#':
                    len_ = 0
                    c1, c2, c3, c4 = '\0', '\0', '\0', '\0'
                    for p in range(i):
                        if c1 == '\0': c1 = S[p]
                        if S[p] == c1: len_ += 1
                    for p in range(i + 1, j):
                        if c2 == '\0': c2 = S[p]
                        if S[p] == c2: len_ += 1
                    for p in range(j + 1, k):
                        if c3 == '\0': c3 = S[p]
                        if S[p] == c3: len_ += 1
                    for p in range(k + 1, n):
                        if c4 == '\0': c4 = S[p]
                        if S[p] == c4: len_ += 1
                    maxLen = max(maxLen, len_ + 3)
